import numpy as np
import matplotlib.pyplot as plt


def plot_sensis(vega_aad, vega_bump, vanna_aad, vanna_bump, title, title1, title2, title3, title4):
    layout = [
        ['A', 'B'],
        ['C', 'D']
    ]

    vega_aad = np.round(vega_aad, 5)
    vega_bump = np.round(vega_bump, 5)
    vanna_aad = np.round(vanna_aad, 5)
    vanna_bump = np.round(vanna_bump, 5)

    fig, axd = plt.subplot_mosaic(layout, figsize=(12, 8), constrained_layout=True)
    fig.suptitle("Dupire Asian " + title)

    # Access axes using the keys defined in layout
    axd['A'].set_title(title1)
    axd['A'].set_xlabel("Strike")
    axd['A'].set_ylabel("Maturity")
    strikes = np.array([0.5, 0.6, 0.7, 0.8, 0.9, 1, 1.1, 1.2, 1.3, 1.4, 1.5, 1.6, 1.7, 1.8])
    mats = np.array([0.5, 1, 1.5, 2, 2.5, ])
    axd['A'].set_yticks(range(len(mats)), labels=mats)
    axd['A'].set_xticks(range(len(strikes)), labels=strikes)
    axd['A'].imshow(vega_aad, vmin=-0.14, vmax=0.10)
    for i in range(len(mats)):
        for j in range(len(strikes)):
            color = "white"
            axd['A'].text(j, i, round(vega_aad[i, j], 3), ha="center", va="center", color=color)

    axd['B'].set_title(title2)
    axd['B'].set_xlabel("Strike")
    axd['B'].set_ylabel("Maturity")
    strikes = np.array([0.5, 0.6, 0.7, 0.8, 0.9, 1, 1.1, 1.2, 1.3, 1.4, 1.5, 1.6, 1.7, 1.8])
    mats = np.array([0.5, 1, 1.5, 2, 2.5, ])
    axd['B'].set_yticks(range(len(mats)), labels=mats)
    axd['B'].set_xticks(range(len(strikes)), labels=strikes)
    axd['B'].imshow((vega_aad - vega_bump), vmin=-0.14, vmax=0.10)
    for i in range(len(mats)):
        for j in range(len(strikes)):
            color = "white"
            axd['B'].text(j, i, round((vega_aad-vega_bump)[i, j], 3), ha="center", va="center", color=color)


    axd['C'].set_title(title3)
    axd['C'].set_xlabel("Strike")
    axd['C'].set_ylabel("Maturity")
    strikes = np.array([0.5, 0.6, 0.7, 0.8, 0.9, 1, 1.1, 1.2, 1.3, 1.4, 1.5, 1.6, 1.7, 1.8])
    mats = np.array([0.5, 1, 1.5, 2, 2.5, ])
    axd['C'].set_yticks(range(len(mats)), labels=mats)
    axd['C'].set_xticks(range(len(strikes)), labels=strikes)
    axd['C'].imshow(vanna_aad, vmin=-0.14, vmax=0.10)
    for i in range(len(mats)):
        for j in range(len(strikes)):
            color = "white"
            axd['C'].text(j, i, round(vanna_aad[i, j], 3), ha="center", va="center", color=color)

    axd['D'].set_title(title4)
    axd['D'].set_xlabel("Strike")
    axd['D'].set_ylabel("Maturity")
    axd['D'].set_yticks(range(len(mats)), labels=mats)
    axd['D'].set_xticks(range(len(strikes)), labels=strikes)
    axd['D'].imshow((vanna_aad-vanna_bump), vmin=-0.14, vmax=0.10)
    for i in range(len(mats)):
        for j in range(len(strikes)):
            color = "white"
            axd['D'].text(j, i, round((vanna_aad-vanna_bump)[i, j], 3), ha="center", va="center", color=color)

    plt.show()


